// ─── NORMALIZAR MENSAJE ENTRANTE ─────────────────────────────────────────
// Soporta tanto Meta Cloud API como Twilio
const body = $input.first().json;

let from = '';
let messageText = '';
let messageId = '';
let provider = 'unknown';

// ── Meta Cloud API ──
if (body.entry && body.entry[0]?.changes) {
  provider = 'meta';
  const change = body.entry[0].changes[0];
  const msg = change.value?.messages?.[0];
  if (!msg) {
    return [{ json: { skip: true } }];
  }
  from = msg.from;
  messageText = msg.text?.body || '';
  messageId = msg.id;
}

// ── Twilio ──
if (body.From && body.Body) {
  provider = 'twilio';
  from = body.From.replace('whatsapp:', '');
  messageText = body.Body;
  messageId = body.MessageSid;
}

if (!from || !messageText) {
  return [{ json: { skip: true } }];
}

return [{
  json: {
    from,
    messageText: messageText.trim(),
    messageId,
    provider,
    skip: false,
    timestamp: new Date().toISOString()
  }
}];

// ─── PREPARAR HISTORIAL DE CONVERSACIÓN ──────────────────────────────────
const sessionRaw = $input.first().json;
const userMessage = $('Normalizar Mensaje').first().json.messageText;
const from = $('Normalizar Mensaje').first().json.from;

let history = [];
try {
  if (sessionRaw.value) {
    history = JSON.parse(sessionRaw.value);
  }
} catch(e) {
  history = [];
}

// Agregar mensaje del usuario al historial
history.push({
  role: 'user',
  content: userMessage
});

// Mantener solo los últimos 10 mensajes para no exceder contexto
if (history.length > 10) {
  history = history.slice(-10);
}

return [{
  json: {
    from,
    userMessage,
    history,
    provider: $('Normalizar Mensaje').first().json.provider
  }
}];

// ─── EXTRAER RESPUESTA Y DETECTAR ACCIONES ───────────────────────────────
const response = $input.first().json;
const assistantMessage = response.content?.[0]?.text || 'Lo siento, ocurrió un error. Por favor intenta de nuevo.';

const from = $('Preparar Historial').first().json.from;
const history = $('Preparar Historial').first().json.history;
const provider = $('Preparar Historial').first().json.provider;

// Actualizar historial con respuesta del asistente
const updatedHistory = [...history, {
  role: 'assistant',
  content: assistantMessage
}];

// Detectar acciones especiales
let action = 'RESPONDER';
let actionData = null;
let cleanMessage = assistantMessage;

if (assistantMessage.includes('ACCIÓN:TRANSFERIR_HUMANO')) {
  action = 'TRANSFERIR_HUMANO';
  cleanMessage = assistantMessage.replace('ACCIÓN:TRANSFERIR_HUMANO', '').trim();
}

if (assistantMessage.includes('ACCIÓN:AGENDAR_VISITA')) {
  action = 'AGENDAR_VISITA';
  try {
    const jsonMatch = assistantMessage.match(/\{[\s\S]*\}/);
    if (jsonMatch) actionData = JSON.parse(jsonMatch[0]);
  } catch(e) {}
  cleanMessage = assistantMessage.split('ACCIÓN:AGENDAR_VISITA')[0].trim();
}

if (assistantMessage.includes('ACCIÓN:CREAR_RESERVA')) {
  action = 'CREAR_RESERVA';
  try {
    const jsonMatch = assistantMessage.match(/\{[\s\S]*\}/);
    if (jsonMatch) actionData = JSON.parse(jsonMatch[0]);
  } catch(e) {}
  cleanMessage = assistantMessage.split('ACCIÓN:CREAR_RESERVA')[0].trim();
}

return [{
  json: {
    from,
    provider,
    assistantMessage,
    cleanMessage: cleanMessage || assistantMessage,
    action,
    actionData,
    updatedHistory
  }
}];

