// ─── CONSTRUIR MENSAJE WHATSAPP ──────────────────────────────────────────
const data = $input.first().json;
const prevData = $('Procesar Respuesta IA').first().json;

let message = prevData.cleanMessage;
const from = prevData.from;
const provider = prevData.provider;

// Si llegó de un nodo de Calendar, agregar confirmación
if (data.id || data.htmlLink) {
  if (prevData.action === 'AGENDAR_VISITA') {
    message = prevData.cleanMessage + '\n\n✅ Tu visita ha quedado registrada en nuestro calendario. Te esperamos.';
  } else if (prevData.action === 'CREAR_RESERVA') {
    message = prevData.cleanMessage + '\n\n✅ Tu fecha ha sido bloqueada en nuestro calendario. Un miembro de nuestro equipo te contactará pronto para confirmar tu reserva.';
  }
}

return [{ json: { from, provider, message } }];
